#!/usr/bin/env python3
"""
contract-validator.py - 全局契约校验 Hook 脚本

在工作流节点执行前后验证数据是否符合契约规范。

触发时机:
- PreToolUse (Task): 校验节点输入
- PostToolUse (Task): 校验节点输出
- Stop: 校验工作流最终输出

输出格式:
- 校验通过: {"status": "pass", ...}
- 校验失败: {"status": "fail", "decision": "block", "errors": [...], ...}

使用说明:
此脚本由 cc-wf-factory 生成，放置在用户工作流的 .claude/hooks/ 目录。
需要配合 .claude/contracts/mapping.yaml 和契约 Schema 文件使用。
"""

import json
import os
import sys
from datetime import datetime
from pathlib import Path
from typing import Any, Optional


# 日志配置
LOG_FILE = Path(".context/contract-validator.log")


def log(level: str, message: str, **kwargs) -> None:
    """
    记录日志到 .context/contract-validator.log

    Args:
        level: 日志级别 (DEBUG, INFO, WARN, ERROR)
        message: 日志消息
        **kwargs: 额外的结构化数据
    """
    try:
        # 确保日志目录存在
        LOG_FILE.parent.mkdir(parents=True, exist_ok=True)

        timestamp = datetime.now().isoformat(timespec="milliseconds")

        # 构建日志条目
        entry: dict[str, Any] = {
            "timestamp": timestamp,
            "level": level,
            "message": message,
        }
        if kwargs:
            entry["data"] = kwargs

        # 追加写入日志文件
        with LOG_FILE.open("a", encoding="utf-8") as f:
            f.write(json.dumps(entry, ensure_ascii=False) + "\n")
    except Exception:
        # 日志写入失败不应影响主流程
        pass

try:
    import yaml
except ImportError:
    yaml = None

try:
    import jsonschema
    from jsonschema import validate, ValidationError
except ImportError:
    jsonschema = None
    validate = None
    ValidationError = None


class ContractValidator:
    """契约校验器"""

    def __init__(self, contracts_dir: Path, mapping_file: Path):
        self.contracts_dir = contracts_dir
        self.mapping_file = mapping_file
        self.mapping = self._load_mapping()

    def _load_mapping(self) -> dict:
        """加载契约映射配置"""
        if not self.mapping_file.exists():
            return {"version": "1.0", "nodes": {}}

        content = self.mapping_file.read_text(encoding="utf-8")
        if yaml:
            return yaml.safe_load(content) or {"version": "1.0", "nodes": {}}
        else:
            # Fallback: 尝试 JSON 格式
            try:
                return json.loads(content)
            except json.JSONDecodeError:
                return {"version": "1.0", "nodes": {}}

    def _load_contract_schema(self, contract_name: str) -> Optional[dict]:
        """加载契约 Schema"""
        # 尝试 YAML 格式
        yaml_file = self.contracts_dir / f"{contract_name}.yaml"
        if yaml_file.exists():
            content = yaml_file.read_text(encoding="utf-8")
            if yaml:
                return yaml.safe_load(content)
            else:
                return None

        # 尝试 JSON 格式
        json_file = self.contracts_dir / f"{contract_name}.json"
        if json_file.exists():
            content = json_file.read_text(encoding="utf-8")
            return json.loads(content)

        return None

    def get_contracts_for_node(
        self, node_name: str
    ) -> tuple[Optional[str], Optional[str]]:
        """获取节点的输入/输出契约名称"""
        nodes = self.mapping.get("nodes", {})
        node_config = nodes.get(node_name, {})

        input_contract = node_config.get("input")
        output_contract = node_config.get("output")

        return input_contract, output_contract

    def validate_data(
        self, data: Any, schema: dict
    ) -> tuple[bool, list[dict]]:
        """
        校验数据是否符合 Schema

        Returns:
            (is_valid, errors)
        """
        if jsonschema is None or validate is None or ValidationError is None:
            # 没有 jsonschema 库时，跳过校验
            return True, []

        errors: list[dict] = []
        try:
            validate(instance=data, schema=schema)
            return True, []
        except ValidationError as e:
            schema_dict = e.schema if isinstance(e.schema, dict) else {}
            error_detail = {
                "field": ".".join(str(p) for p in e.absolute_path) or "(root)",
                "expected": str(schema_dict.get("type", e.validator)),
                "actual": str(type(e.instance).__name__),
                "message": e.message,
            }
            errors.append(error_detail)

            # 收集所有错误（包括嵌套错误）
            for suberror in e.context:
                sub_schema = suberror.schema if isinstance(suberror.schema, dict) else {}
                sub_detail = {
                    "field": ".".join(str(p) for p in suberror.absolute_path)
                    or "(root)",
                    "expected": str(sub_schema.get("type", suberror.validator)),
                    "actual": str(type(suberror.instance).__name__),
                    "message": suberror.message,
                }
                errors.append(sub_detail)

            return False, errors


def find_contracts_dir() -> Path:
    """查找契约目录"""
    # 优先使用环境变量指定的项目目录
    project_dir = os.environ.get("CLAUDE_PROJECT_DIR", "")
    if project_dir:
        contracts_dir = Path(project_dir) / ".claude" / "contracts"
        if contracts_dir.exists():
            return contracts_dir

    # 其次尝试当前工作目录
    cwd = Path.cwd()
    contracts_dir = cwd / ".claude" / "contracts"
    if contracts_dir.exists():
        return contracts_dir

    # 最后返回默认路径（即使不存在）
    return Path(project_dir or cwd) / ".claude" / "contracts"


def extract_node_name(tool_input: dict) -> Optional[str]:
    """从 Task 工具输入中提取节点名称"""
    # Task 工具的 subagent_type 参数就是 Agent/节点名称
    return tool_input.get("subagent_type")


def extract_data_to_validate(
    hook_event: str, tool_input: dict, tool_output: Any
) -> Optional[Any]:
    """
    提取需要校验的数据

    PreToolUse: 校验 Task 的 prompt 中是否有符合契约的数据
    PostToolUse: 校验 Task 的输出结果
    """
    if hook_event == "PreToolUse":
        # 对于输入校验，我们检查 prompt 中是否包含 JSON 数据
        prompt = tool_input.get("prompt", "")
        # 尝试从 prompt 中提取 JSON
        return try_extract_json_from_text(prompt)

    elif hook_event == "PostToolUse":
        # 对于输出校验，我们检查工具输出
        if tool_output:
            # tool_output 可能直接是结果，或在某个字段中
            if isinstance(tool_output, dict):
                # 尝试常见的输出字段
                for field in ["result", "output", "data", "content"]:
                    if field in tool_output:
                        result = tool_output[field]
                        if isinstance(result, str):
                            return try_extract_json_from_text(result)
                        return result
                # 如果没有特定字段，返回整个输出
                return tool_output
            # tool_output 不是 dict 类型
            if isinstance(tool_output, str):
                return try_extract_json_from_text(tool_output)
            return tool_output

    return None


def try_extract_json_from_text(text: str) -> Optional[Any]:
    """尝试从文本中提取 JSON 数据"""
    if not text:
        return None

    # 直接尝试解析整个文本
    try:
        return json.loads(text)
    except json.JSONDecodeError:
        pass

    # 尝试查找 JSON 代码块
    import re

    json_block_pattern = r"```(?:json)?\s*\n?([\s\S]*?)\n?```"
    matches = re.findall(json_block_pattern, text)
    for match in matches:
        try:
            return json.loads(match.strip())
        except json.JSONDecodeError:
            continue

    # 尝试查找独立的 JSON 对象
    brace_start = text.find("{")
    if brace_start >= 0:
        # 找到匹配的闭合括号
        depth = 0
        for i, char in enumerate(text[brace_start:], brace_start):
            if char == "{":
                depth += 1
            elif char == "}":
                depth -= 1
                if depth == 0:
                    try:
                        return json.loads(text[brace_start : i + 1])
                    except json.JSONDecodeError:
                        break

    return None


def generate_suggestion(errors: list[dict]) -> str:
    """生成修复建议"""
    if not errors:
        return ""

    suggestions = []
    for error in errors[:3]:  # 只取前 3 个错误
        field = error.get("field", "unknown")
        expected = error.get("expected", "unknown")
        message = error.get("message", "")

        if "required" in message.lower():
            suggestions.append(f"添加必需字段 '{field}'")
        elif "type" in message.lower():
            suggestions.append(f"将字段 '{field}' 的类型修改为 {expected}")
        elif "minLength" in message.lower() or "minimum" in message.lower():
            suggestions.append(f"确保字段 '{field}' 满足最小值/长度要求")
        else:
            suggestions.append(f"修复字段 '{field}': {message}")

    return "; ".join(suggestions)


def main():
    """主函数"""
    # 读取 stdin 输入
    try:
        input_data = json.load(sys.stdin)
    except json.JSONDecodeError as e:
        # 无法解析输入，直接通过
        log("ERROR", "无法解析输入", error=str(e))
        result = {
            "continue": True,
            "systemMessage": f"contract-validator: 无法解析输入 ({e})",
        }
        print(json.dumps(result))
        return

    # 获取 Hook 事件信息
    hook_event = input_data.get("hook_event_name", "")
    tool_name = input_data.get("tool_name", "")
    tool_input = input_data.get("tool_input", {})
    tool_output = input_data.get("tool_result")  # PostToolUse 时有值

    log("DEBUG", "收到 Hook 事件", hook_event=hook_event, tool_name=tool_name)

    # 只处理 Task 工具调用
    if tool_name != "Task":
        result = {"continue": True}
        print(json.dumps(result))
        return

    # 提取节点名称
    node_name = extract_node_name(tool_input)
    if not node_name:
        log("WARN", "未找到节点名称，跳过校验")
        result = {
            "continue": True,
            "systemMessage": "contract-validator: 未找到节点名称，跳过校验",
        }
        print(json.dumps(result))
        return

    log("INFO", "开始校验节点", node=node_name, event=hook_event)

    # 初始化校验器
    contracts_dir = find_contracts_dir()
    mapping_file = contracts_dir / "mapping.yaml"
    validator = ContractValidator(contracts_dir, mapping_file)

    # 获取节点的契约配置
    input_contract, output_contract = validator.get_contracts_for_node(node_name)

    # 确定需要校验的契约
    check_type = "input" if hook_event == "PreToolUse" else "output"
    contract_name = input_contract if check_type == "input" else output_contract

    # 如果没有配置契约，跳过校验
    if not contract_name:
        result = {
            "continue": True,
            "systemMessage": f"contract-validator: 节点 '{node_name}' 无 {check_type} 契约配置",
        }
        print(json.dumps(result))
        return

    # 加载契约 Schema
    schema = validator._load_contract_schema(contract_name)
    if not schema:
        result = {
            "continue": True,
            "systemMessage": f"contract-validator: 未找到契约 '{contract_name}'",
        }
        print(json.dumps(result))
        return

    # 提取需要校验的数据
    data = extract_data_to_validate(hook_event, tool_input, tool_output)

    # 如果没有数据可校验，对于输入校验跳过，对于输出校验失败
    if data is None:
        if check_type == "input":
            result = {
                "continue": True,
                "systemMessage": f"contract-validator: 节点 '{node_name}' 输入中未找到 JSON 数据",
            }
        else:
            result = {
                "continue": True,
                "hookSpecificOutput": {"permissionDecision": "deny"},
                "systemMessage": f"contract-validator: 节点 '{node_name}' 输出中未找到符合契约的数据",
            }
        print(json.dumps(result))
        return

    # 执行校验
    is_valid, errors = validator.validate_data(data, schema)

    if is_valid:
        # 校验通过
        log("INFO", "校验通过", node=node_name, check_type=check_type, contract=contract_name)
        result = {
            "continue": True,
            "systemMessage": f"contract-validator: 节点 '{node_name}' {check_type} 校验通过",
        }
        print(json.dumps(result))
    else:
        # 校验失败
        suggestion = generate_suggestion(errors)
        error_summary = "; ".join(e.get("message", "")[:100] for e in errors[:3])

        log(
            "ERROR",
            "校验失败",
            node=node_name,
            check_type=check_type,
            contract=contract_name,
            errors=errors,
            suggestion=suggestion,
        )

        result = {
            "continue": True,
            "hookSpecificOutput": {"permissionDecision": "deny"},
            "systemMessage": (
                f"contract-validator: 节点 '{node_name}' {check_type} 校验失败\n"
                f"契约: {contract_name}\n"
                f"错误: {error_summary}\n"
                f"建议: {suggestion}"
            ),
        }

        # 同时输出详细错误到 stderr（会被 Claude 看到）
        detailed_error = {
            "status": "fail",
            "node": node_name,
            "check_type": check_type,
            "contract": contract_name,
            "errors": errors,
            "suggestion": suggestion,
        }
        print(json.dumps(detailed_error), file=sys.stderr)
        print(json.dumps(result))


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""
wf-state.py - 工作流状态治理 Hook 脚本

自动维护工作流执行状态文件，支持进度追踪和断点续传。

触发时机:
- UserPromptSubmit: 检测工作流启动
- PreToolUse (Task): 记录节点开始
- PostToolUse (Task): 记录节点完成/失败
- Stop: 记录工作流完成

输出:
- .context/state.md: 状态文件（Markdown + YAML frontmatter）

使用说明:
此脚本由 cc-wf-factory 生成，放置在用户工作流的 .claude/hooks/ 目录。
状态文件采用 Markdown 格式，人类可直接查看。
"""

import json
import os
import sys
import tempfile
from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Optional

try:
    import yaml
except ImportError:
    yaml = None


class WorkflowState:
    """工作流状态管理器"""

    def __init__(self, state_file: Path):
        self.state_file = state_file
        self.state = self._load_state()

    def _load_state(self) -> dict:
        """加载现有状态"""
        if not self.state_file.exists():
            return self._create_empty_state()

        try:
            content = self.state_file.read_text(encoding="utf-8")
            return self._parse_state_file(content)
        except Exception:
            return self._create_empty_state()

    def _create_empty_state(self) -> dict:
        """创建空状态"""
        return {
            "workflow": "",
            "status": "pending",
            "started_at": None,
            "updated_at": None,
            "completed_at": None,
            "current_node": None,
            "total_nodes": 0,
            "completed_nodes": 0,
            "nodes": {},  # {node_name: {status, started_at, completed_at, summary}}
            "logs": [],  # [{node, event, timestamp, message}]
        }

    def _parse_state_file(self, content: str) -> dict:
        """解析状态文件"""
        # 提取 YAML frontmatter
        if content.startswith("---"):
            parts = content.split("---", 2)
            if len(parts) >= 3:
                frontmatter = parts[1].strip()
                if yaml:
                    state = yaml.safe_load(frontmatter) or {}
                else:
                    # 简单解析
                    state = {}
                    for line in frontmatter.split("\n"):
                        if ": " in line:
                            key, value = line.split(": ", 1)
                            state[key.strip()] = value.strip()

                # 确保所有必需字段存在
                base = self._create_empty_state()
                base.update(state)

                # 保留 nodes 和 logs（它们在 frontmatter 中可能不完整）
                if "nodes" not in base or not isinstance(base["nodes"], dict):
                    base["nodes"] = {}
                if "logs" not in base or not isinstance(base["logs"], list):
                    base["logs"] = []

                return base

        return self._create_empty_state()

    def _get_timestamp(self) -> str:
        """获取当前时间戳"""
        return datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")

    def _get_time_display(self) -> str:
        """获取显示用时间"""
        return datetime.now().strftime("%H:%M:%S")

    def start_workflow(self, workflow_name: str, total_nodes: int = 0):
        """开始工作流"""
        now = self._get_timestamp()
        self.state["workflow"] = workflow_name
        self.state["status"] = "running"
        self.state["started_at"] = now
        self.state["updated_at"] = now
        self.state["total_nodes"] = total_nodes
        self.state["completed_nodes"] = 0
        self.state["current_node"] = None

        self._add_log("workflow", "start", f"工作流 '{workflow_name}' 启动")

    def start_node(self, node_name: str):
        """开始节点执行"""
        now = self._get_timestamp()
        self.state["current_node"] = node_name
        self.state["updated_at"] = now
        self.state["status"] = "running"

        if node_name not in self.state["nodes"]:
            self.state["nodes"][node_name] = {}

        self.state["nodes"][node_name].update({
            "status": "running",
            "started_at": now,
            "completed_at": None,
            "summary": None,
        })

        self._add_log(node_name, "start", f"节点 '{node_name}' 开始执行")

    def complete_node(self, node_name: str, success: bool = True, summary: str = ""):
        """完成节点执行"""
        now = self._get_timestamp()
        self.state["updated_at"] = now

        if node_name in self.state["nodes"]:
            self.state["nodes"][node_name].update({
                "status": "completed" if success else "failed",
                "completed_at": now,
                "summary": summary or ("执行成功" if success else "执行失败"),
            })

        if success:
            self.state["completed_nodes"] = self.state.get("completed_nodes", 0) + 1

        status_text = "完成" if success else "失败"
        self._add_log(node_name, "complete", f"节点 '{node_name}' {status_text}")

        # 如果当前节点完成，清除 current_node
        if self.state.get("current_node") == node_name:
            self.state["current_node"] = None

    def complete_workflow(self, success: bool = True):
        """完成工作流"""
        now = self._get_timestamp()
        self.state["status"] = "completed" if success else "failed"
        self.state["updated_at"] = now
        self.state["completed_at"] = now
        self.state["current_node"] = None

        status_text = "完成" if success else "失败"
        self._add_log("workflow", "complete", f"工作流 {status_text}")

    def _add_log(self, node: str, event: str, message: str):
        """添加日志条目"""
        self.state["logs"].append({
            "node": node,
            "event": event,
            "timestamp": self._get_time_display(),
            "message": message,
        })

    def save(self):
        """保存状态文件（原子写入）"""
        # 确保目录存在
        self.state_file.parent.mkdir(parents=True, exist_ok=True)

        # 生成文件内容
        content = self._generate_state_file()

        # 原子写入：先写入临时文件，再重命名
        fd, tmp_path = tempfile.mkstemp(
            dir=self.state_file.parent,
            prefix=".state_",
            suffix=".tmp"
        )
        try:
            with os.fdopen(fd, "w", encoding="utf-8") as f:
                f.write(content)
            # 重命名（原子操作）
            os.replace(tmp_path, self.state_file)
        except Exception:
            # 清理临时文件
            if os.path.exists(tmp_path):
                os.unlink(tmp_path)
            raise

    def _generate_state_file(self) -> str:
        """生成状态文件内容"""
        # YAML frontmatter
        frontmatter = {
            "workflow": self.state.get("workflow", ""),
            "status": self.state.get("status", "pending"),
            "started_at": self.state.get("started_at"),
            "updated_at": self.state.get("updated_at"),
            "completed_at": self.state.get("completed_at"),
            "current_node": self.state.get("current_node"),
            "total_nodes": self.state.get("total_nodes", 0),
            "completed_nodes": self.state.get("completed_nodes", 0),
        }

        if yaml:
            frontmatter_str = yaml.dump(frontmatter, default_flow_style=False, allow_unicode=True)
        else:
            # 简单格式化
            lines = []
            for k, v in frontmatter.items():
                if v is None:
                    lines.append(f"{k}: null")
                elif isinstance(v, str):
                    lines.append(f"{k}: {v}")
                else:
                    lines.append(f"{k}: {v}")
            frontmatter_str = "\n".join(lines)

        # 状态图标
        status_icons = {
            "pending": "⏳ 待执行",
            "running": "🔄 运行中",
            "completed": "✅ 已完成",
            "failed": "❌ 失败",
            "paused": "⏸️ 已暂停",
        }

        node_status_icons = {
            "pending": "⏳ 待执行",
            "running": "🔄 执行中",
            "completed": "✅ 完成",
            "failed": "❌ 失败",
        }

        status = self.state.get("status", "pending")
        status_display = status_icons.get(status, status)

        workflow_name = self.state.get("workflow", "unknown")
        total = self.state.get("total_nodes", 0)
        completed = self.state.get("completed_nodes", 0)
        current = self.state.get("current_node", "-")

        # Markdown 正文
        body_parts = [
            f"# 工作流执行状态",
            "",
            "## 执行概览",
            f"- **工作流**: {workflow_name}",
            f"- **状态**: {status_display}",
            f"- **进度**: {completed}/{total} 节点完成",
            f"- **当前节点**: {current or '-'}",
            "",
            "## 节点状态",
            "",
            "| 节点 | 状态 | 开始时间 | 完成时间 | 备注 |",
            "|------|------|----------|----------|------|",
        ]

        # 节点表格
        nodes = self.state.get("nodes", {})
        for node_name, node_info in nodes.items():
            node_status = node_info.get("status", "pending")
            status_icon = node_status_icons.get(node_status, node_status)
            started = node_info.get("started_at", "-")
            if started and started != "-":
                # 只显示时间部分
                started = started.split("T")[1].replace("Z", "") if "T" in started else started
            completed_at = node_info.get("completed_at", "-")
            if completed_at and completed_at != "-":
                completed_at = completed_at.split("T")[1].replace("Z", "") if "T" in completed_at else completed_at
            summary = node_info.get("summary", "-") or "-"
            body_parts.append(f"| {node_name} | {status_icon} | {started} | {completed_at} | {summary} |")

        # 如果没有节点，显示提示
        if not nodes:
            body_parts.append("| - | - | - | - | 暂无节点记录 |")

        # 执行日志
        body_parts.extend([
            "",
            "## 执行日志",
            "",
        ])

        logs = self.state.get("logs", [])
        if logs:
            # 按节点分组显示日志
            current_node = None
            for log in logs:
                node = log.get("node", "unknown")
                if node != current_node:
                    current_node = node
                    if node == "workflow":
                        body_parts.append(f"### 工作流事件")
                    else:
                        body_parts.append(f"### {node}")
                    body_parts.append("")

                timestamp = log.get("timestamp", "")
                message = log.get("message", "")
                body_parts.append(f"- **{timestamp}**: {message}")
            body_parts.append("")
        else:
            body_parts.append("暂无日志记录")
            body_parts.append("")

        # 组合完整文件
        return f"---\n{frontmatter_str}---\n\n" + "\n".join(body_parts)


def find_state_file() -> Path:
    """查找状态文件路径"""
    project_dir = os.environ.get("CLAUDE_PROJECT_DIR", "")
    if project_dir:
        return Path(project_dir) / ".context" / "state.md"
    return Path.cwd() / ".context" / "state.md"


def extract_node_name(tool_input: dict) -> Optional[str]:
    """从 Task 工具输入中提取节点名称"""
    return tool_input.get("subagent_type")


def extract_workflow_name(user_prompt: str) -> Optional[str]:
    """
    从用户输入中提取工作流名称

    识别模式:
    - /workflow-name
    - 执行 workflow-name 工作流
    - 运行 workflow-name
    """
    if not user_prompt:
        return None

    # 检查是否是 slash command
    if user_prompt.startswith("/"):
        # /workflow-name 或 /workflow-name args
        parts = user_prompt[1:].split(None, 1)
        if parts:
            return parts[0]

    # 其他模式暂不识别（可扩展）
    return None


def check_node_success(tool_output: Any) -> tuple[bool, str]:
    """
    检查节点执行是否成功

    Returns:
        (success, summary)
    """
    if tool_output is None:
        return True, "执行完成"

    if isinstance(tool_output, dict):
        # 检查常见的错误标识
        if tool_output.get("error"):
            return False, str(tool_output.get("error"))[:100]
        if tool_output.get("status") == "failed":
            return False, tool_output.get("message", "执行失败")[:100]
        if tool_output.get("status") == "error":
            return False, tool_output.get("message", "执行出错")[:100]

        # 尝试提取摘要
        summary = tool_output.get("summary") or tool_output.get("message") or "执行完成"
        if isinstance(summary, str) and len(summary) > 100:
            summary = summary[:97] + "..."
        return True, summary

    if isinstance(tool_output, str):
        # 检查是否包含错误关键词
        lower_output = tool_output.lower()
        if "error" in lower_output or "failed" in lower_output or "exception" in lower_output:
            return False, tool_output[:100] if len(tool_output) > 100 else tool_output
        return True, tool_output[:100] if len(tool_output) > 100 else tool_output

    return True, "执行完成"


def main():
    """主函数"""
    # 读取 stdin 输入
    try:
        input_data = json.load(sys.stdin)
    except json.JSONDecodeError as e:
        result = {
            "continue": True,
            "systemMessage": f"wf-state: 无法解析输入 ({e})",
        }
        print(json.dumps(result))
        return

    # 获取 Hook 事件信息
    hook_event = input_data.get("hook_event_name", "")
    tool_name = input_data.get("tool_name", "")
    tool_input = input_data.get("tool_input", {})
    tool_output = input_data.get("tool_result")
    user_prompt = input_data.get("prompt", "")  # UserPromptSubmit 事件的用户输入

    # 初始化状态管理器
    state_file = find_state_file()
    state_manager = WorkflowState(state_file)

    try:
        if hook_event == "UserPromptSubmit":
            # 检测工作流启动
            workflow_name = extract_workflow_name(user_prompt)
            if workflow_name:
                state_manager.start_workflow(workflow_name)
                state_manager.save()
                result = {
                    "continue": True,
                    "systemMessage": f"wf-state: 工作流 '{workflow_name}' 已启动",
                }
            else:
                # 不是工作流命令，忽略
                result = {"continue": True}

        elif hook_event == "PreToolUse" and tool_name == "Task":
            # 记录节点开始
            node_name = extract_node_name(tool_input)
            if node_name:
                state_manager.start_node(node_name)
                state_manager.save()
                result = {
                    "continue": True,
                    "systemMessage": f"wf-state: 节点 '{node_name}' 开始执行",
                }
            else:
                result = {"continue": True}

        elif hook_event == "PostToolUse" and tool_name == "Task":
            # 记录节点完成
            node_name = extract_node_name(tool_input)
            if node_name:
                success, summary = check_node_success(tool_output)
                state_manager.complete_node(node_name, success, summary)
                state_manager.save()
                status_text = "完成" if success else "失败"
                result = {
                    "continue": True,
                    "systemMessage": f"wf-state: 节点 '{node_name}' {status_text}",
                }
            else:
                result = {"continue": True}

        elif hook_event == "Stop":
            # 记录工作流完成
            # 检查是否有失败的节点
            nodes = state_manager.state.get("nodes", {})
            has_failure = any(
                n.get("status") == "failed" for n in nodes.values()
            )
            state_manager.complete_workflow(success=not has_failure)
            state_manager.save()
            status_text = "完成" if not has_failure else "失败"
            result = {
                "continue": True,
                "systemMessage": f"wf-state: 工作流 {status_text}",
            }

        else:
            # 其他事件，忽略
            result = {"continue": True}

    except Exception as e:
        # 状态更新失败不应阻塞工作流
        result = {
            "continue": True,
            "systemMessage": f"wf-state: 状态更新失败 ({e})",
        }

    print(json.dumps(result))


if __name__ == "__main__":
    main()

# Hook 资源文件

此目录包含 cc-wf-factory 生成工作流时使用的 Hook 脚本模板。

## 文件说明

### contract-validator.py

全局契约校验脚本，由 `cc-settings-builder` Agent 复制到用户工作流的 `.claude/hooks/` 目录。

**功能**：
- PreToolUse (Task): 校验节点输入数据
- PostToolUse (Task): 校验节点输出数据

**依赖**：
- Python 3.8+
- pyyaml
- jsonschema

**使用方式**：
1. `cc-settings-builder` 将此文件复制到 `.claude/hooks/contract-validator.py`
2. 配置 `settings.json` 中的 Hook 配置
3. 用户工作流运行时自动触发契约校验

## 配置示例

生成的 `settings.json` 中的 Hook 配置：

```json
{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Task",
        "hooks": [
          {
            "type": "command",
            "command": "python ${CLAUDE_PROJECT_ROOT}/.claude/hooks/contract-validator.py",
            "timeout": 30
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": "Task",
        "hooks": [
          {
            "type": "command",
            "command": "python ${CLAUDE_PROJECT_ROOT}/.claude/hooks/contract-validator.py",
            "timeout": 30
          }
        ]
      }
    ]
  }
}
```

#!/usr/bin/env python3
"""
contract-validator.py - 全局契约校验 Hook 脚本

在工作流节点执行前后验证数据是否符合契约规范。

触发时机:
- UserPromptSubmit: 校验工作流输入
- PreToolUse (Task): 校验节点输入
- SubagentStop: 校验节点输出
- Stop: 校验工作流输出

退出码处理:
- UserPromptSubmit/PreToolUse: exit(2) + stderr 阻止执行
- SubagentStop/Stop: exit(0) + JSON {"decision": "block", "reason": "..."} 阻止结束

使用说明:
此脚本由 cc-wf-factory 生成，放置在用户工作流的 .claude/hooks/ 目录。
需要配合 .claude/contracts/ 目录中的契约文件使用。
"""

import argparse
import json
import os
import re
import subprocess
import sys
from datetime import datetime
from pathlib import Path
from typing import Any, Optional


# 日志配置
LOG_FILE = Path(".context/contract-validator.log")


def log(level: str, message: str, **kwargs) -> None:
    """
    记录日志到 .context/contract-validator.log

    Args:
        level: 日志级别 (DEBUG, INFO, WARN, ERROR)
        message: 日志消息
        **kwargs: 额外的结构化数据
    """
    try:
        LOG_FILE.parent.mkdir(parents=True, exist_ok=True)

        timestamp = datetime.now().isoformat(timespec="milliseconds")

        entry: dict[str, Any] = {
            "timestamp": timestamp,
            "level": level,
            "message": message,
        }
        if kwargs:
            entry["data"] = kwargs

        with LOG_FILE.open("a", encoding="utf-8") as f:
            f.write(json.dumps(entry, ensure_ascii=False) + "\n")
    except Exception:
        pass


try:
    import yaml
except ImportError:
    yaml = None

try:
    import jsonschema
    from jsonschema import ValidationError, validate
except ImportError:
    jsonschema = None
    validate = None
    ValidationError = None


class ContractValidator:
    """契约校验器"""

    def __init__(self, contracts_dir: Path):
        self.contracts_dir = contracts_dir

    def load_contract(self, contract_name: str) -> Optional[dict]:
        """加载契约文件"""
        yaml_file = self.contracts_dir / f"{contract_name}.yaml"
        if yaml_file.exists():
            content = yaml_file.read_text(encoding="utf-8")
            if yaml:
                return yaml.safe_load(content)
            return None

        json_file = self.contracts_dir / f"{contract_name}.json"
        if json_file.exists():
            content = json_file.read_text(encoding="utf-8")
            return json.loads(content)

        return None

    def validate_schema(self, data: Any, schema: dict) -> tuple[bool, list[dict]]:
        """
        JSON Schema 结构校验

        Returns:
            (is_valid, errors)
        """
        if jsonschema is None or validate is None or ValidationError is None:
            return True, []

        errors: list[dict] = []
        try:
            validate(instance=data, schema=schema)
            return True, []
        except ValidationError as e:
            schema_dict = e.schema if isinstance(e.schema, dict) else {}
            error_detail = {
                "field": ".".join(str(p) for p in e.absolute_path) or "(root)",
                "expected": str(schema_dict.get("type", e.validator)),
                "actual": str(type(e.instance).__name__),
                "message": e.message,
            }
            errors.append(error_detail)

            for suberror in e.context:
                sub_schema = (
                    suberror.schema if isinstance(suberror.schema, dict) else {}
                )
                sub_detail = {
                    "field": ".".join(str(p) for p in suberror.absolute_path)
                    or "(root)",
                    "expected": str(sub_schema.get("type", suberror.validator)),
                    "actual": str(type(suberror.instance).__name__),
                    "message": suberror.message,
                }
                errors.append(sub_detail)

            return False, errors

    def run_validator_script(
        self, script_path: str, data: Any
    ) -> tuple[bool, list[dict]]:
        """
        执行自定义校验脚本

        脚本接收 JSON 数据作为 stdin，输出 JSON 结果到 stdout:
        - 通过: {"valid": true}
        - 失败: {"valid": false, "errors": [...]}
        """
        full_path = self.contracts_dir / script_path
        if not full_path.exists():
            return True, []

        try:
            result = subprocess.run(
                ["python", str(full_path)],
                input=json.dumps(data),
                capture_output=True,
                text=True,
                timeout=30,
            )

            if result.returncode != 0:
                return False, [{"message": f"校验脚本执行失败: {result.stderr}"}]

            output = json.loads(result.stdout)
            if output.get("valid", True):
                return True, []
            return False, output.get("errors", [{"message": "自定义校验失败"}])
        except subprocess.TimeoutExpired:
            return False, [{"message": "校验脚本执行超时"}]
        except Exception as e:
            return False, [{"message": f"校验脚本执行异常: {str(e)}"}]


def find_contracts_dir() -> Path:
    """查找契约目录"""
    project_dir = os.environ.get("CLAUDE_PROJECT_DIR", "")
    if project_dir:
        contracts_dir = Path(project_dir) / ".claude" / "contracts"
        if contracts_dir.exists():
            return contracts_dir

    cwd = Path.cwd()
    contracts_dir = cwd / ".claude" / "contracts"
    if contracts_dir.exists():
        return contracts_dir

    return Path(project_dir or cwd) / ".claude" / "contracts"


def try_extract_json_from_text(text: str) -> Optional[Any]:
    """尝试从文本中提取 JSON 数据"""
    if not text:
        return None

    try:
        return json.loads(text)
    except json.JSONDecodeError:
        pass

    json_block_pattern = r"```(?:json)?\s*\n?([\s\S]*?)\n?```"
    matches = re.findall(json_block_pattern, text)
    for match in matches:
        try:
            return json.loads(match.strip())
        except json.JSONDecodeError:
            continue

    brace_start = text.find("{")
    if brace_start >= 0:
        depth = 0
        for i, char in enumerate(text[brace_start:], brace_start):
            if char == "{":
                depth += 1
            elif char == "}":
                depth -= 1
                if depth == 0:
                    try:
                        return json.loads(text[brace_start : i + 1])
                    except json.JSONDecodeError:
                        break

    return None


def read_last_assistant_message(transcript_path: str) -> Optional[str]:
    """从 transcript 文件读取最后一条 assistant 消息"""
    try:
        path = Path(transcript_path)
        if not path.exists():
            return None

        last_assistant_content = None
        with path.open("r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    entry = json.loads(line)
                    if entry.get("role") == "assistant":
                        content = entry.get("content", "")
                        if isinstance(content, list):
                            text_parts = [
                                block.get("text", "")
                                for block in content
                                if block.get("type") == "text"
                            ]
                            content = "\n".join(text_parts)
                        last_assistant_content = content
                except json.JSONDecodeError:
                    continue

        return last_assistant_content
    except Exception as e:
        log("ERROR", "读取 transcript 失败", path=transcript_path, error=str(e))
        return None


def generate_suggestion(errors: list[dict]) -> str:
    """生成修复建议"""
    if not errors:
        return ""

    suggestions = []
    for error in errors[:3]:
        field = error.get("field", "unknown")
        expected = error.get("expected", "unknown")
        message = error.get("message", "")

        if "required" in message.lower():
            suggestions.append(f"添加必需字段 '{field}'")
        elif "type" in message.lower():
            suggestions.append(f"将字段 '{field}' 的类型修改为 {expected}")
        elif "minLength" in message.lower() or "minimum" in message.lower():
            suggestions.append(f"确保字段 '{field}' 满足最小值/长度要求")
        else:
            suggestions.append(f"修复字段 '{field}': {message}")

    return "; ".join(suggestions)


def format_error_message(
    node_name: str, contract_name: str, errors: list[dict], check_type: str
) -> str:
    """格式化错误消息"""
    suggestion = generate_suggestion(errors)
    error_summary = "; ".join(e.get("message", "")[:100] for e in errors[:3])

    return (
        f"contract-validator: 节点 '{node_name}' {check_type} 校验失败\n"
        f"契约: {contract_name}\n"
        f"错误: {error_summary}\n"
        f"建议: {suggestion}"
    )


def block_with_exit(message: str) -> None:
    """使用 exit(2) 阻止执行 (UserPromptSubmit/PreToolUse)"""
    print(message, file=sys.stderr)
    sys.exit(2)


def block_with_json(reason: str) -> None:
    """使用 JSON 阻止结束 (SubagentStop/Stop)"""
    result = {"decision": "block", "reason": reason}
    print(json.dumps(result))
    sys.exit(0)


def allow_continue(message: str = "") -> None:
    """允许继续执行"""
    if message:
        result = {"continue": True, "systemMessage": message}
    else:
        result = {"continue": True}
    print(json.dumps(result))
    sys.exit(0)


def handle_user_prompt_submit(input_data: dict, validator: ContractValidator) -> None:
    """处理 UserPromptSubmit 事件"""
    # 工作流输入校验需要从工作流配置获取契约名称
    # 这里需要实现工作流配置解析逻辑
    # 目前简化处理：跳过校验
    log("DEBUG", "UserPromptSubmit 事件，跳过校验")
    allow_continue()


def handle_pre_tool_use(input_data: dict, validator: ContractValidator) -> None:
    """处理 PreToolUse 事件"""
    tool_name = input_data.get("tool_name", "")
    tool_input = input_data.get("tool_input", {})

    if tool_name != "Task":
        allow_continue()

    node_name = tool_input.get("subagent_type")
    if not node_name:
        allow_continue("contract-validator: 未找到节点名称，跳过校验")

    # 读取节点的 agent 文件获取 input_contract
    project_dir = os.environ.get("CLAUDE_PROJECT_DIR", str(Path.cwd()))
    agent_file = Path(project_dir) / ".claude" / "agents" / f"{node_name}.md"

    if not agent_file.exists():
        allow_continue(f"contract-validator: 未找到节点配置 {node_name}")

    agent_content = agent_file.read_text(encoding="utf-8")
    input_contract = extract_frontmatter_field(agent_content, "input_contract")

    if not input_contract:
        allow_continue(f"contract-validator: 节点 '{node_name}' 无输入契约配置")

    contract = validator.load_contract(input_contract)
    if not contract:
        allow_continue(f"contract-validator: 未找到契约 '{input_contract}'")

    # 从 tool_input 提取校验数据
    prompt = tool_input.get("prompt", "")
    data = try_extract_json_from_text(prompt)

    if data is None:
        allow_continue(f"contract-validator: 节点 '{node_name}' 输入中未找到 JSON 数据")

    # 执行校验
    all_errors = []

    # 1. Schema 校验
    schema = contract.get("schema")
    if schema:
        is_valid, errors = validator.validate_schema(data, schema)
        if not is_valid:
            all_errors.extend(errors)

    # 2. 自定义校验脚本
    validator_script = contract.get("validator_script")
    if validator_script and not all_errors:
        is_valid, errors = validator.run_validator_script(validator_script, data)
        if not is_valid:
            all_errors.extend(errors)

    if all_errors:
        log(
            "ERROR",
            "PreToolUse 校验失败",
            node=node_name,
            contract=input_contract,
            errors=all_errors,
        )
        error_msg = format_error_message(node_name, input_contract, all_errors, "输入")
        block_with_exit(error_msg)
    else:
        log("INFO", "PreToolUse 校验通过", node=node_name, contract=input_contract)
        allow_continue(f"contract-validator: 节点 '{node_name}' 输入校验通过")


def handle_subagent_stop(
    input_data: dict, validator: ContractValidator, args: argparse.Namespace
) -> None:
    """处理 SubagentStop 事件"""
    contract_name = args.contract
    node_name = args.node or input_data.get("agent_id", "unknown")

    if not contract_name:
        allow_continue("contract-validator: 未指定契约名称，跳过校验")

    contract = validator.load_contract(contract_name)
    if not contract:
        allow_continue(f"contract-validator: 未找到契约 '{contract_name}'")

    # 从 agent_transcript_path 读取最后一条 assistant 消息
    transcript_path = input_data.get("agent_transcript_path")
    if not transcript_path:
        block_with_json(f"contract-validator: 未找到节点 '{node_name}' 的 transcript")

    last_message = read_last_assistant_message(transcript_path)
    if not last_message:
        block_with_json(f"contract-validator: 无法读取节点 '{node_name}' 的输出")

    data = try_extract_json_from_text(last_message)
    if data is None:
        block_with_json(
            f"contract-validator: 节点 '{node_name}' 输出中未找到符合契约的数据"
        )

    # 执行校验
    all_errors = []

    # 1. Schema 校验
    schema = contract.get("schema")
    if schema:
        is_valid, errors = validator.validate_schema(data, schema)
        if not is_valid:
            all_errors.extend(errors)

    # 2. 自定义校验脚本
    validator_script = contract.get("validator_script")
    if validator_script and not all_errors:
        is_valid, errors = validator.run_validator_script(validator_script, data)
        if not is_valid:
            all_errors.extend(errors)

    if all_errors:
        log(
            "ERROR",
            "SubagentStop 校验失败",
            node=node_name,
            contract=contract_name,
            errors=all_errors,
        )
        error_msg = format_error_message(node_name, contract_name, all_errors, "输出")
        block_with_json(error_msg)
    else:
        log("INFO", "SubagentStop 校验通过", node=node_name, contract=contract_name)
        allow_continue(f"contract-validator: 节点 '{node_name}' 输出校验通过")


def handle_stop(input_data: dict, validator: ContractValidator) -> None:
    """处理 Stop 事件（工作流输出校验）"""
    # 工作流输出校验需要从工作流配置获取契约名称
    # 目前简化处理：跳过校验
    log("DEBUG", "Stop 事件，跳过校验")
    allow_continue()


def extract_frontmatter_field(content: str, field: str) -> Optional[str]:
    """从 Markdown 文件的 YAML frontmatter 中提取字段值"""
    if not content.startswith("---"):
        return None

    end_marker = content.find("---", 3)
    if end_marker == -1:
        return None

    frontmatter = content[3:end_marker].strip()

    if yaml:
        try:
            data = yaml.safe_load(frontmatter)
            return data.get(field)
        except Exception:
            pass

    # Fallback: 简单正则匹配
    pattern = rf"^{field}:\s*(.+)$"
    match = re.search(pattern, frontmatter, re.MULTILINE)
    if match:
        return match.group(1).strip()

    return None


def parse_args() -> argparse.Namespace:
    """解析命令行参数"""
    parser = argparse.ArgumentParser(description="契约校验脚本")
    parser.add_argument("--contract", type=str, help="契约名称")
    parser.add_argument("--node", type=str, help="节点名称")
    return parser.parse_args()


def main():
    """主函数"""
    args = parse_args()

    # 读取 stdin 输入
    try:
        input_data = json.load(sys.stdin)
    except json.JSONDecodeError as e:
        log("ERROR", "无法解析输入", error=str(e))
        allow_continue(f"contract-validator: 无法解析输入 ({e})")

    hook_event = input_data.get("hook_event_name", "")
    log("DEBUG", "收到 Hook 事件", hook_event=hook_event, args=vars(args))

    # 初始化校验器
    contracts_dir = find_contracts_dir()
    validator = ContractValidator(contracts_dir)

    # 根据事件类型分发处理
    if hook_event == "UserPromptSubmit":
        handle_user_prompt_submit(input_data, validator)
    elif hook_event == "PreToolUse":
        handle_pre_tool_use(input_data, validator)
    elif hook_event == "SubagentStop":
        handle_subagent_stop(input_data, validator, args)
    elif hook_event == "Stop":
        handle_stop(input_data, validator)
    else:
        log("WARN", "未知的 Hook 事件", hook_event=hook_event)
        allow_continue()


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""
wf-state.py - 工作流状态治理 Hook 脚本

自动维护工作流执行状态文件，支持进度追踪和断点续传。

触发时机:
- UserPromptSubmit: 检测工作流启动
- PreToolUse (Task): 记录节点开始
- PostToolUse (Task): 记录节点完成/失败，提取输出写入文件
- Stop: 记录工作流完成

输出:
- .context/state.md: 状态文件（Markdown + YAML frontmatter）
- .context/outputs/{node-name}.json: 节点原始输出
- .context/outputs/{node-name}.md: 节点可读输出

使用说明:
此脚本由 cc-wf-factory 生成，放置在用户工作流的 .claude/hooks/ 目录。
状态文件采用 Markdown 格式，人类可直接查看。
"""

import json
import os
import sys
import tempfile
from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Optional

try:
    import yaml
except ImportError:
    yaml = None


def get_project_dir() -> Path:
    """获取项目目录"""
    project_dir = os.environ.get("CLAUDE_PROJECT_DIR", "")
    if project_dir:
        return Path(project_dir)
    return Path.cwd()


def ensure_outputs_dir() -> Path:
    """确保输出目录存在"""
    outputs_dir = get_project_dir() / ".context" / "outputs"
    outputs_dir.mkdir(parents=True, exist_ok=True)
    return outputs_dir


def write_node_output(node_name: str, output_data: Any) -> Optional[str]:
    """
    将节点输出写入文件

    Args:
        node_name: 节点名称
        output_data: 节点输出数据

    Returns:
        输出文件的相对路径（.json），若写入失败则返回 None
    """
    outputs_dir = ensure_outputs_dir()
    json_path = outputs_dir / f"{node_name}.json"
    md_path = outputs_dir / f"{node_name}.md"

    timestamp = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")

    # 写入 JSON 文件（原始格式）
    try:
        if isinstance(output_data, str):
            # 尝试解析为 JSON
            try:
                parsed = json.loads(output_data)
                json_content = json.dumps(parsed, ensure_ascii=False, indent=2)
            except json.JSONDecodeError:
                # 不是有效 JSON，包装为字符串
                json_content = json.dumps({"content": output_data}, ensure_ascii=False, indent=2)
        elif output_data is None:
            json_content = json.dumps({"content": None}, ensure_ascii=False, indent=2)
        else:
            json_content = json.dumps(output_data, ensure_ascii=False, indent=2)

        _atomic_write(json_path, json_content)
    except Exception:
        return None

    # 写入 Markdown 文件（可读格式）
    try:
        md_content = _generate_output_markdown(node_name, output_data, timestamp)
        _atomic_write(md_path, md_content)
    except Exception:
        pass  # Markdown 写入失败不影响主流程

    # 返回相对路径
    return f".context/outputs/{node_name}.json"


def _generate_output_markdown(node_name: str, output_data: Any, timestamp: str) -> str:
    """生成节点输出的 Markdown 格式"""
    lines = [
        f"# 节点输出: {node_name}",
        "",
        "## 元信息",
        f"- 执行时间: {timestamp}",
        "- 状态: 成功",
        "",
        "## 输出数据",
        "",
    ]

    if output_data is None:
        lines.append("_无输出数据_")
    elif isinstance(output_data, str):
        # 尝试解析为 JSON 并格式化
        try:
            parsed = json.loads(output_data)
            lines.append("```json")
            lines.append(json.dumps(parsed, ensure_ascii=False, indent=2))
            lines.append("```")
        except json.JSONDecodeError:
            # 不是有效 JSON，直接显示
            lines.append(output_data)
    elif isinstance(output_data, dict) or isinstance(output_data, list):
        lines.append("```json")
        lines.append(json.dumps(output_data, ensure_ascii=False, indent=2))
        lines.append("```")
    else:
        lines.append(str(output_data))

    lines.append("")
    return "\n".join(lines)


def _atomic_write(file_path: Path, content: str):
    """原子写入文件"""
    file_path.parent.mkdir(parents=True, exist_ok=True)
    fd, tmp_path = tempfile.mkstemp(
        dir=file_path.parent,
        prefix=".tmp_",
        suffix=".tmp"
    )
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as f:
            f.write(content)
        os.replace(tmp_path, file_path)
    except Exception:
        if os.path.exists(tmp_path):
            os.unlink(tmp_path)
        raise


class WorkflowState:
    """工作流状态管理器"""

    def __init__(self, state_file: Path):
        self.state_file = state_file
        self.state = self._load_state()

    def _load_state(self) -> dict:
        """加载现有状态"""
        if not self.state_file.exists():
            return self._create_empty_state()

        try:
            content = self.state_file.read_text(encoding="utf-8")
            return self._parse_state_file(content)
        except Exception:
            return self._create_empty_state()

    def _create_empty_state(self) -> dict:
        """创建空状态"""
        return {
            "workflow": "",
            "session_id": None,  # 断点恢复的关键
            "status": "pending",
            "started_at": None,
            "updated_at": None,
            "completed_at": None,
            "current_node": None,
            "progress": "0/0",
            "total_nodes": 0,
            "completed_nodes": 0,
            "outputs": {},  # {node_name: output_file_path}
            "nodes": {},  # {node_name: {status, started_at, completed_at, summary}}
            "logs": [],  # [{node, event, timestamp, message}]
        }

    def _parse_state_file(self, content: str) -> dict:
        """解析状态文件"""
        # 提取 YAML frontmatter
        if content.startswith("---"):
            parts = content.split("---", 2)
            if len(parts) >= 3:
                frontmatter = parts[1].strip()
                if yaml:
                    state = yaml.safe_load(frontmatter) or {}
                else:
                    # 简单解析
                    state = {}
                    for line in frontmatter.split("\n"):
                        if ": " in line:
                            key, value = line.split(": ", 1)
                            state[key.strip()] = value.strip()

                # 确保所有必需字段存在
                base = self._create_empty_state()
                base.update(state)

                # 保留 nodes、logs、outputs（它们在 frontmatter 中可能不完整）
                if "nodes" not in base or not isinstance(base["nodes"], dict):
                    base["nodes"] = {}
                if "logs" not in base or not isinstance(base["logs"], list):
                    base["logs"] = []
                if "outputs" not in base or not isinstance(base["outputs"], dict):
                    base["outputs"] = {}

                return base

        return self._create_empty_state()

    def _get_timestamp(self) -> str:
        """获取当前时间戳"""
        return datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")

    def _get_time_display(self) -> str:
        """获取显示用时间"""
        return datetime.now().strftime("%H:%M:%S")

    def start_workflow(self, workflow_name: str, session_id: Optional[str] = None, total_nodes: int = 0):
        """开始工作流"""
        now = self._get_timestamp()
        self.state["workflow"] = workflow_name
        self.state["session_id"] = session_id
        self.state["status"] = "running"
        self.state["started_at"] = now
        self.state["updated_at"] = now
        self.state["total_nodes"] = total_nodes
        self.state["completed_nodes"] = 0
        self.state["current_node"] = None
        self.state["progress"] = f"0/{total_nodes}"
        self.state["outputs"] = {}

        self._add_log("workflow", "start", f"工作流 '{workflow_name}' 启动")

    def start_node(self, node_name: str):
        """开始节点执行"""
        now = self._get_timestamp()
        self.state["current_node"] = node_name
        self.state["updated_at"] = now
        self.state["status"] = "running"

        if node_name not in self.state["nodes"]:
            self.state["nodes"][node_name] = {}

        self.state["nodes"][node_name].update({
            "status": "running",
            "started_at": now,
            "completed_at": None,
            "summary": None,
        })

        self._add_log(node_name, "start", f"节点 '{node_name}' 开始执行")

    def complete_node(self, node_name: str, success: bool = True, summary: str = "", output_path: Optional[str] = None):
        """完成节点执行"""
        now = self._get_timestamp()
        self.state["updated_at"] = now

        if node_name in self.state["nodes"]:
            self.state["nodes"][node_name].update({
                "status": "completed" if success else "failed",
                "completed_at": now,
                "summary": summary or ("执行成功" if success else "执行失败"),
            })

        if success:
            self.state["completed_nodes"] = self.state.get("completed_nodes", 0) + 1

        # 更新进度
        total = self.state.get("total_nodes", 0)
        completed = self.state.get("completed_nodes", 0)
        self.state["progress"] = f"{completed}/{total}"

        # 记录输出文件路径
        if output_path:
            self.state["outputs"][node_name] = output_path

        status_text = "完成" if success else "失败"
        self._add_log(node_name, "complete", f"节点 '{node_name}' {status_text}")

        # 如果当前节点完成，清除 current_node
        if self.state.get("current_node") == node_name:
            self.state["current_node"] = None

    def complete_workflow(self, success: bool = True):
        """完成工作流"""
        now = self._get_timestamp()
        self.state["status"] = "completed" if success else "failed"
        self.state["updated_at"] = now
        self.state["completed_at"] = now
        self.state["current_node"] = None

        status_text = "完成" if success else "失败"
        self._add_log("workflow", "complete", f"工作流 {status_text}")

    def _add_log(self, node: str, event: str, message: str):
        """添加日志条目"""
        self.state["logs"].append({
            "node": node,
            "event": event,
            "timestamp": self._get_time_display(),
            "message": message,
        })

    def save(self):
        """保存状态文件（原子写入）"""
        # 确保目录存在
        self.state_file.parent.mkdir(parents=True, exist_ok=True)

        # 生成文件内容
        content = self._generate_state_file()

        # 原子写入：先写入临时文件，再重命名
        fd, tmp_path = tempfile.mkstemp(
            dir=self.state_file.parent,
            prefix=".state_",
            suffix=".tmp"
        )
        try:
            with os.fdopen(fd, "w", encoding="utf-8") as f:
                f.write(content)
            # 重命名（原子操作）
            os.replace(tmp_path, self.state_file)
        except Exception:
            # 清理临时文件
            if os.path.exists(tmp_path):
                os.unlink(tmp_path)
            raise

    def _generate_state_file(self) -> str:
        """生成状态文件内容"""
        # 计算 progress
        total = self.state.get("total_nodes", 0)
        completed = self.state.get("completed_nodes", 0)
        progress = f"{completed}/{total}"

        # YAML frontmatter（按需求文档格式）
        frontmatter = {
            "workflow": self.state.get("workflow", ""),
            "session_id": self.state.get("session_id"),
            "status": self.state.get("status", "pending"),
            "started_at": self.state.get("started_at"),
            "updated_at": self.state.get("updated_at"),
            "completed_at": self.state.get("completed_at"),
            "current_node": self.state.get("current_node"),
            "progress": progress,
            "outputs": self.state.get("outputs", {}),
        }

        if yaml:
            frontmatter_str = yaml.dump(frontmatter, default_flow_style=False, allow_unicode=True)
        else:
            # 简单格式化
            lines = []
            for k, v in frontmatter.items():
                if v is None:
                    lines.append(f"{k}: null")
                elif isinstance(v, str):
                    lines.append(f"{k}: {v}")
                else:
                    lines.append(f"{k}: {v}")
            frontmatter_str = "\n".join(lines)

        # 状态图标
        status_icons = {
            "pending": "⏳ 待执行",
            "running": "🔄 运行中",
            "completed": "✅ 已完成",
            "failed": "❌ 失败",
            "paused": "⏸️ 已暂停",
        }

        node_status_icons = {
            "pending": "⏳ 待执行",
            "running": "🔄 执行中",
            "completed": "✅ 完成",
            "failed": "❌ 失败",
        }

        status = self.state.get("status", "pending")
        status_display = status_icons.get(status, status)

        workflow_name = self.state.get("workflow", "unknown")
        session_id = self.state.get("session_id", "-")
        current = self.state.get("current_node", "-")
        outputs = self.state.get("outputs", {})

        # Markdown 正文
        body_parts = [
            f"# 工作流执行状态",
            "",
            "## 执行概览",
            f"- **工作流**: {workflow_name}",
            f"- **会话**: {session_id or '-'}",
            f"- **状态**: {status_display}",
            f"- **进度**: {progress} 节点完成",
            f"- **当前节点**: {current or '-'}",
            "",
            "## 节点状态",
            "",
            "| 节点 | 状态 | 开始时间 | 完成时间 | 输出 |",
            "|------|------|----------|----------|------|",
        ]

        # 节点表格
        nodes = self.state.get("nodes", {})
        for node_name, node_info in nodes.items():
            node_status = node_info.get("status", "pending")
            status_icon = node_status_icons.get(node_status, node_status)
            started = node_info.get("started_at", "-")
            if started and started != "-":
                # 只显示时间部分
                started = started.split("T")[1].replace("Z", "") if "T" in started else started
            completed_at = node_info.get("completed_at", "-")
            if completed_at and completed_at != "-":
                completed_at = completed_at.split("T")[1].replace("Z", "") if "T" in completed_at else completed_at

            # 输出链接
            if node_name in outputs:
                output_link = f"[查看]({outputs[node_name]})"
            else:
                output_link = "-"
            body_parts.append(f"| {node_name} | {status_icon} | {started} | {completed_at} | {output_link} |")

        # 如果没有节点，显示提示
        if not nodes:
            body_parts.append("| - | - | - | - | 暂无节点记录 |")

        # 执行日志
        body_parts.extend([
            "",
            "## 执行日志",
            "",
        ])

        logs = self.state.get("logs", [])
        if logs:
            # 按节点分组显示日志
            current_node = None
            for log in logs:
                node = log.get("node", "unknown")
                if node != current_node:
                    current_node = node
                    if node == "workflow":
                        body_parts.append(f"### 工作流事件")
                    else:
                        body_parts.append(f"### {node}")
                    body_parts.append("")

                timestamp = log.get("timestamp", "")
                message = log.get("message", "")
                body_parts.append(f"- **{timestamp}**: {message}")
            body_parts.append("")
        else:
            body_parts.append("暂无日志记录")
            body_parts.append("")

        # 组合完整文件
        return f"---\n{frontmatter_str}---\n\n" + "\n".join(body_parts)


def find_state_file() -> Path:
    """查找状态文件路径"""
    project_dir = os.environ.get("CLAUDE_PROJECT_DIR", "")
    if project_dir:
        return Path(project_dir) / ".context" / "state.md"
    return Path.cwd() / ".context" / "state.md"


def extract_node_name(tool_input: dict) -> Optional[str]:
    """从 Task 工具输入中提取节点名称"""
    return tool_input.get("subagent_type")


def extract_workflow_name(user_prompt: str) -> Optional[str]:
    """
    从用户输入中提取工作流名称

    识别模式:
    - /workflow-name
    - 执行 workflow-name 工作流
    - 运行 workflow-name
    """
    if not user_prompt:
        return None

    # 检查是否是 slash command
    if user_prompt.startswith("/"):
        # /workflow-name 或 /workflow-name args
        parts = user_prompt[1:].split(None, 1)
        if parts:
            return parts[0]

    # 其他模式暂不识别（可扩展）
    return None


def check_node_success(tool_output: Any) -> tuple[bool, str]:
    """
    检查节点执行是否成功

    Returns:
        (success, summary)
    """
    if tool_output is None:
        return True, "执行完成"

    if isinstance(tool_output, dict):
        # 检查常见的错误标识
        if tool_output.get("error"):
            return False, str(tool_output.get("error"))[:100]
        if tool_output.get("status") == "failed":
            return False, tool_output.get("message", "执行失败")[:100]
        if tool_output.get("status") == "error":
            return False, tool_output.get("message", "执行出错")[:100]

        # 尝试提取摘要
        summary = tool_output.get("summary") or tool_output.get("message") or "执行完成"
        if isinstance(summary, str) and len(summary) > 100:
            summary = summary[:97] + "..."
        return True, summary

    if isinstance(tool_output, str):
        # 检查是否包含错误关键词
        lower_output = tool_output.lower()
        if "error" in lower_output or "failed" in lower_output or "exception" in lower_output:
            return False, tool_output[:100] if len(tool_output) > 100 else tool_output
        return True, tool_output[:100] if len(tool_output) > 100 else tool_output

    return True, "执行完成"


def main():
    """主函数"""
    # 读取 stdin 输入
    try:
        input_data = json.load(sys.stdin)
    except json.JSONDecodeError as e:
        result = {
            "continue": True,
            "systemMessage": f"wf-state: 无法解析输入 ({e})",
        }
        print(json.dumps(result))
        return

    # 获取 Hook 事件信息
    hook_event = input_data.get("hook_event_name", "")
    tool_name = input_data.get("tool_name", "")
    tool_input = input_data.get("tool_input", {})
    tool_output = input_data.get("tool_response")  # PostToolUse 时的节点输出
    if tool_output is None:
        tool_output = input_data.get("tool_result")  # 兼容旧字段名
    user_prompt = input_data.get("prompt", "")  # UserPromptSubmit 事件的用户输入
    session_id = input_data.get("session_id")  # 会话 ID

    # 初始化状态管理器
    state_file = find_state_file()
    state_manager = WorkflowState(state_file)

    try:
        if hook_event == "UserPromptSubmit":
            # 检测工作流启动
            workflow_name = extract_workflow_name(user_prompt)
            if workflow_name:
                state_manager.start_workflow(workflow_name, session_id=session_id)
                state_manager.save()
                result = {
                    "continue": True,
                    "systemMessage": f"wf-state: 工作流 '{workflow_name}' 已启动",
                }
            else:
                # 不是工作流命令，忽略
                result = {"continue": True}

        elif hook_event == "PreToolUse" and tool_name == "Task":
            # 记录节点开始
            node_name = extract_node_name(tool_input)
            if node_name:
                state_manager.start_node(node_name)
                state_manager.save()
                result = {
                    "continue": True,
                    "systemMessage": f"wf-state: 节点 '{node_name}' 开始执行",
                }
            else:
                result = {"continue": True}

        elif hook_event == "PostToolUse" and tool_name == "Task":
            # 记录节点完成，提取并写入输出
            node_name = extract_node_name(tool_input)
            if node_name:
                success, summary = check_node_success(tool_output)

                # 写入节点输出文件
                output_path = None
                if success and tool_output is not None:
                    output_path = write_node_output(node_name, tool_output)

                state_manager.complete_node(node_name, success, summary, output_path=output_path)
                state_manager.save()
                status_text = "完成" if success else "失败"
                result = {
                    "continue": True,
                    "systemMessage": f"wf-state: 节点 '{node_name}' {status_text}",
                }
            else:
                result = {"continue": True}

        elif hook_event == "Stop":
            # 记录工作流完成
            # 检查是否有失败的节点
            nodes = state_manager.state.get("nodes", {})
            has_failure = any(
                n.get("status") == "failed" for n in nodes.values()
            )
            state_manager.complete_workflow(success=not has_failure)
            state_manager.save()
            status_text = "完成" if not has_failure else "失败"
            result = {
                "continue": True,
                "systemMessage": f"wf-state: 工作流 {status_text}",
            }

        else:
            # 其他事件，忽略
            result = {"continue": True}

    except Exception as e:
        # 状态更新失败不应阻塞工作流
        result = {
            "continue": True,
            "systemMessage": f"wf-state: 状态更新失败 ({e})",
        }

    print(json.dumps(result))


if __name__ == "__main__":
    main()

