        - 通过: {"valid": true}
        - 失败: {"valid": false, "errors": [...]}
        """
        full_path = self.contracts_dir / script_path
        if not full_path.exists():
            return True, []

        try:
            result = subprocess.run(
                ["python", str(full_path)],
                input=json.dumps(data),
                capture_output=True,
                text=True,
                timeout=30,
            )

            if result.returncode != 0:
                return False, [{"message": f"校验脚本执行失败: {result.stderr}"}]

            output = json.loads(result.stdout)
            if output.get("valid", True):
                return True, []
            return False, output.get("errors", [{"message": "自定义校验失败"}])
        except subprocess.TimeoutExpired:
            return False, [{"message": "校验脚本执行超时"}]
        except Exception as e:
            return False, [{"message": f"校验脚本执行异常: {str(e)}"}]


def find_contracts_dir() -> Path:
    """查找契约目录"""
    project_dir = os.environ.get("CLAUDE_PROJECT_DIR", "")
    if project_dir:
        contracts_dir = Path(project_dir) / ".claude" / "contracts"
        if contracts_dir.exists():
            return contracts_dir

    cwd = Path.cwd()
    contracts_dir = cwd / ".claude" / "contracts"
    if contracts_dir.exists():
        return contracts_dir

    return Path(project_dir or cwd) / ".claude" / "contracts"


def try_extract_json_from_text(text: str) -> Optional[Any]:
    """尝试从文本中提取 JSON 数据"""
    if not text:
        return None

    try:
        return json.loads(text)
    except json.JSONDecodeError:
        pass

    json_block_pattern = r"```(?:json)?\s*\n?([\s\S]*?)\n?```"
    matches = re.findall(json_block_pattern, text)
    for match in matches:
        try:
            return json.loads(match.strip())
        except json.JSONDecodeError:
            continue

    brace_start = text.find("{")
    if brace_start >= 0:
        depth = 0
        for i, char in enumerate(text[brace_start:], brace_start):
            if char == "{":
                depth += 1
            elif char == "}":
                depth -= 1
                if depth == 0:
                    try:
                        return json.loads(text[brace_start : i + 1])
                    except json.JSONDecodeError:
                        break

    return None


def read_last_assistant_message(transcript_path: str) -> Optional[str]:
    """从 transcript 文件读取最后一条 assistant 消息"""
    try:
        path = Path(transcript_path)
        if not path.exists():
            return None

        last_assistant_content = None
        with path.open("r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    entry = json.loads(line)
                    if entry.get("role") == "assistant":
                        content = entry.get("content", "")
                        if isinstance(content, list):
                            text_parts = [
                                block.get("text", "")
                                for block in content
                                if block.get("type") == "text"
                            ]
                            content = "\n".join(text_parts)
                        last_assistant_content = content
                except json.JSONDecodeError:
                    continue

        return last_assistant_content
    except Exception as e:
        log("ERROR", "读取 transcript 失败", path=transcript_path, error=str(e))
        return None


def generate_suggestion(errors: list[dict]) -> str:
    """生成修复建议"""
    if not errors:
        return ""

    suggestions = []
    for error in errors[:3]:
        field = error.get("field", "unknown")
        expected = error.get("expected", "unknown")
        message = error.get("message", "")

        if "required" in message.lower():
            suggestions.append(f"添加必需字段 '{field}'")
        elif "type" in message.lower():
            suggestions.append(f"将字段 '{field}' 的类型修改为 {expected}")
        elif "minLength" in message.lower() or "minimum" in message.lower():
            suggestions.append(f"确保字段 '{field}' 满足最小值/长度要求")
        else:
            suggestions.append(f"修复字段 '{field}': {message}")

    return "; ".join(suggestions)


def format_error_message(
    node_name: str, contract_name: str, errors: list[dict], check_type: str
) -> str:
    """格式化错误消息"""
    suggestion = generate_suggestion(errors)
    error_summary = "; ".join(e.get("message", "")[:100] for e in errors[:3])

    return (
        f"contract-validator: 节点 '{node_name}' {check_type} 校验失败\n"
        f"契约: {contract_name}\n"
        f"错误: {error_summary}\n"
        f"建议: {suggestion}"
    )


def block_with_exit(message: str) -> None:
    """使用 exit(2) 阻止执行 (UserPromptSubmit/PreToolUse)"""
    print(message, file=sys.stderr)
    sys.exit(2)


def block_with_json(reason: str) -> None:
    """使用 JSON 阻止结束 (SubagentStop/Stop)"""
    result = {"decision": "block", "reason": reason}
    print(json.dumps(result))
    sys.exit(0)


def allow_continue(message: str = "") -> None:
    """允许继续执行"""
    if message:
        result = {"continue": True, "systemMessage": message}
    else:
        result = {"continue": True}
    print(json.dumps(result))
    sys.exit(0)


def handle_user_prompt_submit(input_data: dict, validator: ContractValidator) -> None:
    """处理 UserPromptSubmit 事件"""
    # 工作流输入校验需要从工作流配置获取契约名称
    # 这里需要实现工作流配置解析逻辑
    # 目前简化处理：跳过校验
    log("DEBUG", "UserPromptSubmit 事件，跳过校验")
    allow_continue()


def handle_pre_tool_use(input_data: dict, validator: ContractValidator) -> None:
    """处理 PreToolUse 事件"""
    tool_name = input_data.get("tool_name", "")
    tool_input = input_data.get("tool_input", {})

    if tool_name != "Task":
        allow_continue()

    node_name = tool_input.get("subagent_type")
    if not node_name:
        allow_continue("contract-validator: 未找到节点名称，跳过校验")

    # 读取节点的 agent 文件获取 input_contract
    project_dir = os.environ.get("CLAUDE_PROJECT_DIR", str(Path.cwd()))
    agent_file = Path(project_dir) / ".claude" / "agents" / f"{node_name}.md"

    if not agent_file.exists():
        allow_continue(f"contract-validator: 未找到节点配置 {node_name}")

    agent_content = agent_file.read_text(encoding="utf-8")
    input_contract = extract_frontmatter_field(agent_content, "input_contract")

    if not input_contract:
        allow_continue(f"contract-validator: 节点 '{node_name}' 无输入契约配置")

    contract = validator.load_contract(input_contract)
    if not contract:
        allow_continue(f"contract-validator: 未找到契约 '{input_contract}'")

    # 从 tool_input 提取校验数据
    prompt = tool_input.get("prompt", "")
    data = try_extract_json_from_text(prompt)

    if data is None:
        allow_continue(f"contract-validator: 节点 '{node_name}' 输入中未找到 JSON 数据")

    # 执行校验
    all_errors = []

    # 1. Schema 校验
    schema = contract.get("schema")
    if schema:
        is_valid, errors = validator.validate_schema(data, schema)
        if not is_valid:
            all_errors.extend(errors)

    # 2. 自定义校验脚本
    validator_script = contract.get("validator_script")
    if validator_script and not all_errors:
        is_valid, errors = validator.run_validator_script(validator_script, data)
        if not is_valid:
            all_errors.extend(errors)

    if all_errors:
        log(
            "ERROR",
            "PreToolUse 校验失败",
            node=node_name,
            contract=input_contract,
            errors=all_errors,
        )
        error_msg = format_error_message(node_name, input_contract, all_errors, "输入")
        block_with_exit(error_msg)
    else:
        log("INFO", "PreToolUse 校验通过", node=node_name, contract=input_contract)
        allow_continue(f"contract-validator: 节点 '{node_name}' 输入校验通过")


def handle_subagent_stop(
    input_data: dict, validator: ContractValidator, args: argparse.Namespace
) -> None:
    """处理 SubagentStop 事件"""
    contract_name = args.contract
    node_name = args.node or input_data.get("agent_id", "unknown")

    if not contract_name:
        allow_continue("contract-validator: 未指定契约名称，跳过校验")

    contract = validator.load_contract(contract_name)
    if not contract:
        allow_continue(f"contract-validator: 未找到契约 '{contract_name}'")

    # 从 agent_transcript_path 读取最后一条 assistant 消息
    transcript_path = input_data.get("agent_transcript_path")
    if not transcript_path:
        block_with_json(f"contract-validator: 未找到节点 '{node_name}' 的 transcript")

    last_message = read_last_assistant_message(transcript_path)
    if not last_message:
        block_with_json(f"contract-validator: 无法读取节点 '{node_name}' 的输出")

    data = try_extract_json_from_text(last_message)
    if data is None:
        block_with_json(
            f"contract-validator: 节点 '{node_name}' 输出中未找到符合契约的数据"
        )

    # 执行校验
    all_errors = []

    # 1. Schema 校验
    schema = contract.get("schema")
    if schema:
        is_valid, errors = validator.validate_schema(data, schema)
        if not is_valid:
            all_errors.extend(errors)

    # 2. 自定义校验脚本
    validator_script = contract.get("validator_script")
    if validator_script and not all_errors:
        is_valid, errors = validator.run_validator_script(validator_script, data)
        if not is_valid:
            all_errors.extend(errors)

    if all_errors:
        log(
            "ERROR",
            "SubagentStop 校验失败",
            node=node_name,
            contract=contract_name,
            errors=all_errors,
        )
        error_msg = format_error_message(node_name, contract_name, all_errors, "输出")
        block_with_json(error_msg)
    else:
        log("INFO", "SubagentStop 校验通过", node=node_name, contract=contract_name)
        allow_continue(f"contract-validator: 节点 '{node_name}' 输出校验通过")


def handle_stop(input_data: dict, validator: ContractValidator) -> None:
    """处理 Stop 事件（工作流输出校验）"""
    # 工作流输出校验需要从工作流配置获取契约名称
    # 目前简化处理：跳过校验
    log("DEBUG", "Stop 事件，跳过校验")
    allow_continue()


def extract_frontmatter_field(content: str, field: str) -> Optional[str]:
    """从 Markdown 文件的 YAML frontmatter 中提取字段值"""
    if not content.startswith("---"):
        return None

    end_marker = content.find("---", 3)
    if end_marker == -1:
        return None

    frontmatter = content[3:end_marker].strip()

    if yaml:
        try:
            data = yaml.safe_load(frontmatter)
            return data.get(field)
        except Exception:
            pass

    # Fallback: 简单正则匹配
    pattern = rf"^{field}:\s*(.+)$"
    match = re.search(pattern, frontmatter, re.MULTILINE)
    if match:
        return match.group(1).strip()

    return None


def parse_args() -> argparse.Namespace:
    """解析命令行参数"""
    parser = argparse.ArgumentParser(description="契约校验脚本")
    parser.add_argument("--contract", type=str, help="契约名称")
    parser.add_argument("--node", type=str, help="节点名称")
    return parser.parse_args()


def main():
    """主函数"""
    args = parse_args()

    # 读取 stdin 输入
    try:
        input_data = json.load(sys.stdin)
    except json.JSONDecodeError as e:
        log("ERROR", "无法解析输入", error=str(e))
        allow_continue(f"contract-validator: 无法解析输入 ({e})")

    hook_event = input_data.get("hook_event_name", "")
    log("DEBUG", "收到 Hook 事件", hook_event=hook_event, args=vars(args))

    # 初始化校验器
    contracts_dir = find_contracts_dir()
    validator = ContractValidator(contracts_dir)

    # 根据事件类型分发处理
    if hook_event == "UserPromptSubmit":
        handle_user_prompt_submit(input_data, validator)
    elif hook_event == "PreToolUse":
        handle_pre_tool_use(input_data, validator)
    elif hook_event == "SubagentStop":
        handle_subagent_stop(input_data, validator, args)
    elif hook_event == "Stop":
        handle_stop(input_data, validator)
    else:
        log("WARN", "未知的 Hook 事件", hook_event=hook_event)
        allow_continue()


if __name__ == "__main__":
    main()

